// Script Continued Below
function onSubmit() {
	if (g_form.getActionName() == 'RunProcessTemplateModalUIAction') {

		// STRY0086102  - If the form is dirty, ask the user if they would like to save the record
		// If the form is dirty, ask the user if they would like to save the record
		var saveChangeConfirmation = false;
		var saveMsg = getMessage('Tasker - Modal Save Changes Message');
		if(typeof spModal != 'undefined'){
			var serializeChanges = g_form.serialize(true);
			if(serializeChanges.length>0){
				var changeFieldList = [];
				for (var field in serializeChanges) {
					changeFieldList.push(serializeChanges[field].label.trim());
				}
				var fMsg = changeFieldList.join(', ');					
				saveMsg += "  " + fMsg;
				saveChangeConfirmation = true;
			}
		} else if (typeof spModal == 'undefined' && g_form.modified) {
			saveMsg += JSON.stringify(g_form.modifiedFields);
			saveChangeConfirmation = true;
		}

		// use the variable set above here to show confirmation message.
		if(saveChangeConfirmation){				
			if(confirm(saveMsg)){
				g_form.save();
			} else{
				return false;
			}
		}

		// STRY0075793 - implement in Native pages also
		if (typeof spModal != 'undefined' ) {
			spModal.open({
				title: 'Template Instance',
				backdrop:'static',
				widget: 'discovertasker-widget-modal-prompt',
				widgetInput: {process_template_sys_id: g_form.getUniqueValue()},
					buttons: [{label:'Close', cancel: true}]
					});
		// STRY0075793 - implement in Native pages also
		}else{
			// STRY0075793
			var modalForm = new GlideModalForm('Template Instance', 'x_153465_discovert_discover_routing_runtime');
			modalForm.addParm('sysparm_query','routing_template_ref='+g_form.getUniqueValue());
			modalForm.render();
			modalForm.setSysID(-1);
		}
		return false;
	}
}
